html:
{% if doc.docstatus == 1 %}
{% set role_profile = frappe.db.get_value("User", frappe.session.user, "role_profile_name") %}



<main style="width: 700px; margin: 0 auto;" >
<div class="wrap">
  <div class="page">

    {# --- HEADER --- #}
    <div style="display: flex; justify-content: center; margin-bottom: 5px;">
      {% if letter_head and not no_letterhead %}
        <div class="letter-head text-center" style="width:100%; display:flex; justify-content:center;">
          {{ letter_head }}
        </div>
      {% else %}
        {% set logo = frappe.db.get_value('Letter Head', 'logo', 'image') %}
        {% if logo %}
          <div class="text-center">
            <img src="{{ logo }}" style="max-height:25mm; width:auto;">
          </div>
        {% endif %}
      {% endif %}
    </div>

    {# --- TITLE --- #}


    {# --- PATIENT INFO --- #}
    {% set p = frappe.get_doc("Patient", doc.patient) if doc.patient else None %}
    {% set sex = p.sex if p else (doc.patient_sex or "") %}
    {% set age = p.p_age if p else "" %}
    {% set age_type = p.age_type if p else "" %}
    {% set patient_name = p.patient_name if p else (doc.patient_name or "") %}

    <div class="info-card">
      <table class="info-table">
        <tr>
          <td style="width:55%;">
            <div><span class="k">Patient Name</span> : <span class="v">{{ patient_name }}</span></div>
            <div><span class="k">Patient ID</span> : <span class="v">{{ doc.patient or "" }}</span></div>
            <div><span class="k">Sex / Age</span> : <span class="v">{{ sex }}{% if age %} / {{ age }} {{ age_type }}{% endif %}</span></div>
            <div><span class="k">Doctor</span> : <span class="v">{{ doc.practitioner or doc.practitioner_name or doc.referring_practitioner_name or "" }}</span></div>
          </td>
          <td style="width:45%;">
            <div><span class="k">Lab Ref No</span> : <span class="v">{{ doc.lab_ref or "" }}</span></div>
            <div><span class="k">Collected</span> : <span class="v">{{ doc.date or "" }}{% if doc.time_collected %} {{ frappe.format(doc.time_collected, {"fieldtype": "Time"}) }}{% endif %}</span></div>
            <div><span class="k">Reported</span> : <span class="v">{{ doc.date or "" }}{% if doc.time_reported %} {{ frappe.format(doc.time_reported, {"fieldtype": "Time"}) }}{% endif %}</span></div>
            <div>
              <span class="k">Printed</span> :
              <span class="v">
                {{ frappe.utils.now_datetime().strftime("%d-%m-%Y %H:%M:%S") }}
              </span>
            </div>
          </td>
        </tr>
      </table>

        <table class="info-table">
        <tr>
         <div class="title">{{ doc.template or doc.lab_test_name or "Lab" }} Report</div>
        </tr>
      </table>
    </div>

   {# --- CHECK WHICH COLUMNS HAVE DATA --- #}
    {% set ns = namespace(has_test=false, has_event=false, has_normal=false) %}

    {% for r in doc.normal_test_items %}
      {% if r.lab_test_name or r.test %}
        {% set ns.has_test = true %}
      {% endif %}
      {% if r.lab_test_event %}
        {% set ns.has_event = true %}
      {% endif %}
      {% if r.normal_range %}
        {% set ns.has_normal = true %}
      {% endif %}
    {% endfor %}

    {# --- RESULTS TABLE --- #}
    <table class="tbl">
      <thead>
        <tr style="color:black">
          {% if ns.has_test %}
            <th style="color:black; text-align: center;">Test Name</th>
          {% endif %}
          {% if ns.has_event %}
            <th style="color:black">Event</th>
          {% endif %}
          <th style="color:black">Result Value</th>

            <th style="color:black">Normal Range</th>

        </tr>
      </thead>

      <tbody>
        {% for r in doc.normal_test_items %}

          {# GROUP HEADER (MICROSCOPY etc) #}
          {% if r.lab_test_name and not r.lab_test_event and not (r.result_value or r.result_value == 0) %}
            <tr class="test-header">
              {% if ns.has_test %}
                <td>{{ r.lab_test_name }}</td>
              {% endif %}
              {% if ns.has_event %}<td></td>{% endif %}
              <td></td>
              {% if ns.has_normal %}<td></td>{% endif %}
            </tr>

          {# EVENT ROW (WBC, ZEIHL etc) #}
          {% elif r.lab_test_event %}
            <tr>
              {% if ns.has_test %}<td></td>{% endif %}
              {% if ns.has_event %}
                <td class="event-name">

              {% if doc.type == "Group" and not r.result_value %}
                <b>{{ (r.lab_test_event or "").upper() }}</b>
              {% else %}
                {{ (r.lab_test_event or "").upper() }}
              {% endif %}

              {% endif %}
              <td class="result-value">
                {{ r.result_value or ""}}
                {% if r.lab_test_uom %}
                  <span style="font-weight: normal;"> {{ r.lab_test_uom }}</span>
                {% endif %}
              </td>

                <td>{{ r.normal_range or "-" }}</td>

            </tr>

          {# SIMPLE TEST (Calcium, Malaria, etc) #}
          {% else %}
            <tr>
              {% if ns.has_test %}
                <td>{{ r.lab_test_name or r.test or "" }}</td>
              {% endif %}
              {% if ns.has_event %}
                <td></td>
              {% endif %}
              <td class="result-value">
                {{ r.result_value }}
                {% if r.lab_test_uom %}
                  <span style="font-weight: normal;"> {{ r.lab_test_uom }}</span>
                {% endif %}
              </td>

                <td>{{ r.normal_range or "-" }}</td>

            </tr>
          {% endif %}

        {% endfor %}
      </tbody>
    </table>
    {# --- COMMENTS --- #}
    {% if doc.lab_test_comment %}
      <div style="margin-top:8px; border:1px solid #ddd; padding:6px;">
        <b>Comments:</b> <span class="muted">{{ doc.lab_test_comment }}</span>
      </div>
    {% endif %}

    {# --- FOOTER --- #}
    <div class="footer">
      <div class="sign">
        Reported By<br>
        <span class="muted">{{ frappe.get_fullname() }}</span>
      </div>
      <div class="sign">
        Authorized By<br>
        <span class="muted">
          {{ doc.employee_name or "" }}
          {% if doc.employee_designation %}<br>{{ doc.employee_designation }}{% endif %}
        </span>
      </div>
    </div>


  </div>
</div>



{% else %}
  <div style="padding:10px; border:1px solid #999; color:red;"><b>Please Submit if Results are Completed.</b></div>
{% endif %}

</main>
